1	interface Item {
2	  type: string;
3	  material?: string;
4	  enchantment?: number;
5	  cursed?: boolean;
6	}
7	
8	interface QuoteStep {
9	  op: "quote";
10	  items: Item[];
11	}
12	
13	interface Customer {
14	  yearsWithMHPCO: number;
15	}
16	
17	interface Scenario {
18	  customer: Customer;
19	  steps: QuoteStep[];
20	}
21	
22	const BASE_PREMIUM: Record<string, number> = {
23	  sword: 100,
24	  amulet: 60,
25	  staff: 80,
26	  potion: 40,
27	  rune: 25,
28	  moonstone: 25,
29	};
30	
31	const FIRST_INSURANCE_RATE = 0.1;
32	const PROCESSING_FEE = 5;
33	const LOYALTY_THRESHOLD_YEARS = 2;
34	const LOYALTY_DISCOUNT_RATE = 0.2;
35	
36	const COMPONENT_TYPES = ["rune", "moonstone"];
37	const COMPONENT_BLOCK_SIZE = 3;
38	const COMPONENT_BLOCK_PREMIUM = 60;
39	
40	const isComponent = (type: string): boolean => COMPONENT_TYPES.includes(type);
41	
42	const typeBasePremium = (type: string, count: number): number =>
43	  isComponent(type) && count === COMPONENT_BLOCK_SIZE
44	    ? COMPONENT_BLOCK_PREMIUM
45	    : count * BASE_PREMIUM[type];
46	
47	const CURSE_RATE = 0.5;
48	const HIGH_ENCHANTMENT_THRESHOLD = 5;
49	const HIGH_ENCHANTMENT_RATE = 0.3;
50	
51	const surchargeForItem = (item: Item): number => {
52	  const base = BASE_PREMIUM[item.type];
53	  const curse = item.cursed ? CURSE_RATE * base : 0;
54	  const highEnchantment =
55	    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
56	      ? HIGH_ENCHANTMENT_RATE * base
57	      : 0;
58	  return curse + highEnchantment;
59	};
60	
61	const itemSurcharges = (items: Item[]): number =>
62	  items.reduce((sum, item) => sum + surchargeForItem(item), 0);
63	
64	const countByType = (items: Item[]): Map<string, number> => {
65	  const counts = new Map<string, number>();
66	  for (const item of items) {
67	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
68	  }
69	  return counts;
70	};
71	
72	const policyBasePremium = (items: Item[]): number =>
73	  [...countByType(items)].reduce(
74	    (total, [type, count]) => total + typeBasePremium(type, count),
75	    0,
76	  );
77	
78	const isLoyal = (customer: Customer): boolean =>
79	  customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS;
80	
81	const policyModifierRate = (customer: Customer): number =>
82	  FIRST_INSURANCE_RATE - (isLoyal(customer) ? LOYALTY_DISCOUNT_RATE : 0);
83	
84	const quotePremium = (step: QuoteStep, customer: Customer): number => {
85	  const policyBase = policyBasePremium(step.items);
86	  const policyModifiers = policyBase * policyModifierRate(customer);
87	  return Math.ceil(
88	    policyBase + itemSurcharges(step.items) + policyModifiers + PROCESSING_FEE,
89	  );
90	};
91	
92	export const runScenario = (scenario: Scenario): { results: { premium: number }[] } => {
93	  return {
94	    results: scenario.steps.map((step) => ({
95	      premium: quotePremium(step, scenario.customer),
96	    })),
97	  };
98	};
